export function parseArgs(argv) {
  const result = { _: [] }
  let index = 0
  while (index < argv.length) {
    const arg = argv[index]
    if (!arg.startsWith('-')) {
      result._.push(arg)
      index += 1
    } else if (arg.includes('=')) {
      const key = arg.slice(2)
      result[key] = arg.slice(arg.indexOf('=') + 1)
      index += 1
    } else {
      const key = arg.slice(2)
      result[key] = argv[index + 1]
      index += 2
    }
  }
  return result
}

